public void addValue(Object v) {
    if (freqTable == null) {
        throw new NullPointerException("freqTable should not be null");
    }
    try {
        Long count = (Long) freqTable.get(v);
        if (count == null) {
            freqTable.put(v, Long.valueOf(1));
        } else {
            freqTable.put(v, Long.valueOf(count.longValue() + 1));
        }
    } catch (ClassCastException ex) {
        //TreeMap will throw ClassCastException if v is not comparable
        throw new ClassCastException("Value not comparable to existing values.");
    } catch (NullPointerException ex) {
        throw new NullPointerException("Value should not be null");
    }
}

